"use client";

import Badge from "@/components/ui/badge/Badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import type { Customer } from "@/app/(admin)/customers/page";

type Props = {
  customers: Customer[];
  loading: boolean;
  page: number;
  totalPages: number;
  onPageChange: React.Dispatch<React.SetStateAction<number>>;
  onEdit: (customer: Customer) => void;
  onDeactivate: (id: string) => void;
};

export default function CustomersTable({
  customers,
  loading,
  page,
  totalPages,
  onPageChange,
  onEdit,
  onDeactivate,
}: Props) {
  return (
    <div className="overflow-hidden rounded-xl border border-gray-200 bg-white dark:border-white/[0.05] dark:bg-white/[0.03]">
      <div className="max-w-full overflow-x-auto">
        <div className="min-w-[1100px]">
          <Table>
            <TableHeader className="border-b border-gray-100 dark:border-white/[0.05]">
              <TableRow>
                {[
                  "Arabic Name",
                  "English Name",
                  "Mobile",
                  "National ID",
                  "City",
                  "Risk Level",
                  "Status",
                  "Actions",
                ].map((header) => (
                  <TableCell
                    key={header}
                    isHeader
                    className="px-5 py-3 text-start text-theme-xs font-medium text-gray-500 dark:text-gray-400"
                  >
                    {header}
                  </TableCell>
                ))}
              </TableRow>
            </TableHeader>

            <TableBody className="divide-y divide-gray-100 dark:divide-white/[0.05]">
              {loading ? (
                <TableRow>
                  <TableCell className="px-5 py-6 text-center text-gray-500 dark:text-gray-400">
                    Loading customers...
                  </TableCell>
                </TableRow>
              ) : customers.length === 0 ? (
                <TableRow>
                  <TableCell className="px-5 py-6 text-center text-gray-500 dark:text-gray-400">
                    No customers found.
                  </TableCell>
                </TableRow>
              ) : (
                customers.map((customer) => (
                  <TableRow key={customer.id}>
                    <TableCell className="px-5 py-4 text-start">
                      <span className="block text-theme-sm font-medium text-gray-800 dark:text-white/90">
                        {customer.full_name_ar}
                      </span>
                      <span className="block text-theme-xs text-gray-500 dark:text-gray-400">
                        {customer.id}
                      </span>
                    </TableCell>

                    <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                      {customer.full_name_en || "-"}
                    </TableCell>

                    <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                      {customer.mobile_number}
                    </TableCell>

                    <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                      {customer.national_id || "-"}
                    </TableCell>

                    <TableCell className="px-4 py-3 text-theme-sm text-gray-500 dark:text-gray-400">
                      {customer.city || "-"}
                    </TableCell>

                    <TableCell className="px-4 py-3">
                      <Badge
                        size="sm"
                        color={
                          customer.risk_level === "low"
                            ? "success"
                            : customer.risk_level === "medium"
                            ? "warning"
                            : customer.risk_level === "high"
                            ? "error"
                            : "light"
                        }
                      >
                        {customer.risk_level || "unknown"}
                      </Badge>
                    </TableCell>

                    <TableCell className="px-4 py-3">
                      <Badge
                        size="sm"
                        color={
                          customer.status === "active"
                            ? "success"
                            : customer.status === "inactive"
                            ? "error"
                            : "warning"
                        }
                      >
                        {customer.status || "unknown"}
                      </Badge>
                    </TableCell>

                    <TableCell className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <button
                          onClick={() => onEdit(customer)}
                          className="rounded-lg border border-gray-300 px-3 py-1.5 text-sm font-medium text-gray-700 hover:bg-gray-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
                        >
                          Edit
                        </button>

                        <button
                          onClick={() => onDeactivate(customer.id)}
                          className="rounded-lg bg-error-500 px-3 py-1.5 text-sm font-medium text-white hover:bg-error-600"
                        >
                          Deactivate
                        </button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </div>
      </div>

      <div className="flex items-center justify-between border-t border-gray-100 px-5 py-4 dark:border-white/[0.05]">
        <button
          onClick={() => onPageChange((p) => Math.max(p - 1, 1))}
          disabled={page === 1}
          className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
        >
          Previous
        </button>

        <span className="text-sm text-gray-500 dark:text-gray-400">
          Page {page} of {totalPages || 1}
        </span>

        <button
          onClick={() => onPageChange((p) => Math.min(p + 1, totalPages))}
          disabled={page === totalPages || totalPages === 0}
          className="rounded-lg border border-gray-300 px-4 py-2 text-sm font-medium text-gray-700 hover:bg-gray-50 disabled:cursor-not-allowed disabled:opacity-50 dark:border-gray-700 dark:text-gray-400 dark:hover:bg-white/[0.03]"
        >
          Next
        </button>
      </div>
    </div>
  );
}