"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";
import BackToDashboard from "@/components/BackToDashboard";
import { isSuperAdmin } from "@/lib/auth";
import CustomersTable from "@/components/customers/CustomersTable";
import CustomerModal from "@/components/customers/CustomerModal";

export type Customer = {
  id: string;
  full_name_ar: string;
  full_name_en?: string;
  mobile_number: string;
  national_id?: string;
  city?: string;
  address?: string;
  risk_level?: string;
  status?: string;
};

export type CustomerForm = {
  full_name_ar: string;
  full_name_en: string;
  mobile_number: string;
  national_id: string;
  city: string;
  address: string;
};

const emptyForm: CustomerForm = {
  full_name_ar: "",
  full_name_en: "",
  mobile_number: "",
  national_id: "",
  city: "",
  address: "",
};

export default function CustomersPage() {
  const [page, setPage] = useState(1);
  const pageSize = 15;

  const [customers, setCustomers] = useState<Customer[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingCustomer, setEditingCustomer] = useState<Customer | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [error, setError] = useState("");
  const [superAdmin, setSuperAdmin] = useState(false);
  const [form, setForm] = useState<CustomerForm>(emptyForm);

  useEffect(() => {
    loadCustomers();
    setSuperAdmin(isSuperAdmin());
  }, []);

  async function loadCustomers() {
    try {
      setLoading(true);
      setError("");
      const data = await apiFetch("/merchant/customers");
      setCustomers(data);
    } catch (err: any) {
      setError(err.message || "Failed to load customers");
    } finally {
      setLoading(false);
    }
  }

  function openAddModal() {
    setEditingCustomer(null);
    setForm(emptyForm);
    setIsModalOpen(true);
  }

  function openEditModal(customer: Customer) {
    setEditingCustomer(customer);
    setForm({
      full_name_ar: customer.full_name_ar || "",
      full_name_en: customer.full_name_en || "",
      mobile_number: customer.mobile_number || "",
      national_id: customer.national_id || "",
      city: customer.city || "",
      address: customer.address || "",
    });
    setIsModalOpen(true);
  }

  async function saveCustomer(e: React.FormEvent) {
    e.preventDefault();

    try {
      setError("");

      if (editingCustomer) {
        await apiFetch(`/merchant/customers/${editingCustomer.id}`, {
          method: "PATCH",
          body: JSON.stringify(form),
        });
      } else {
        await apiFetch("/merchant/customers", {
          method: "POST",
          body: JSON.stringify(form),
        });
      }

      setIsModalOpen(false);
      setEditingCustomer(null);
      setForm(emptyForm);
      await loadCustomers();
    } catch (err: any) {
      setError(err.message || "Failed to save customer");
    }
  }

  async function deactivateCustomer(id: string) {
    if (!confirm("Deactivate this customer?")) return;

    try {
      setError("");

      await apiFetch(`/merchant/customers/${id}`, {
        method: "DELETE",
      });

      await loadCustomers();
    } catch (err: any) {
      setError(err.message || "Failed to deactivate customer");
    }
  }

  const totalPages = Math.ceil(customers.length / pageSize);

  const paginatedCustomers = customers.slice(
    (page - 1) * pageSize,
    page * pageSize
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-semibold text-gray-800 dark:text-white/90">
            Customers
          </h1>
          <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
            View, add, update, and deactivate customer records.
          </p>
        </div>

        <div className="flex items-center gap-3">
          <BackToDashboard />

          <button
            onClick={openAddModal}
            className="rounded-lg bg-brand-500 px-4 py-2.5 text-sm font-medium text-white hover:bg-brand-600"
          >
            Add Customer
          </button>
        </div>
      </div>

      {error && (
        <div className="rounded-lg border border-error-200 bg-error-50 px-4 py-3 text-sm text-error-700 dark:border-error-500/30 dark:bg-error-500/10 dark:text-error-400">
          {error}
        </div>
      )}

      <CustomersTable
        customers={paginatedCustomers}
        loading={loading}
        page={page}
        totalPages={totalPages}
        onPageChange={setPage}
        onEdit={openEditModal}
        onDeactivate={deactivateCustomer}
      />

      <CustomerModal
        isOpen={isModalOpen}
        superAdmin={superAdmin}
        editingCustomer={editingCustomer}
        form={form}
        setForm={setForm}
        onClose={() => setIsModalOpen(false)}
        onSubmit={saveCustomer}
      />
    </div>
  );
}